<template>
  <div class="w-100 float-left" style="overflow: auto;" id="divNodeFlowChartNew">
    <loader :is-visible="isLoading"></loader>
    <input type="hidden" :value="showFromInvoice" />
    <input type="hidden" :value="showHistory" />
    <div v-if="flowData.length > 0"  style="width: 1805px; min-width: 1400px;">
      <RBillingFlowChart :data="flowData" chart-id="RflowChartNew" chart-class="outer" :isBillingType="isBillingType" />
    </div>
  <div v-else-if="flowData.length <= 0 && !isLoading" class="text-danger text-center" style="padding-top: 50%;" > No Data Found</div>
  </div>
  
</template>

<script>
import RBillingFlowChart from '../../../views/BillingRule/ConfigurationComponent/RBillingFlowChart.vue';
import DataService from "../../../services/DataService";
import html2canvas from "html2canvas";
export default {
  name: 'FlowChartWrapper',
  components: { RBillingFlowChart },
  props: {
    configurationId: {
      type: [String, Number],
      required: false
    },
    isBillingType :{
            type: Boolean,
            required: false
    },
    clientId: {
            type: Number,
            default: false
    }
  },
  data() {
    return {
      flowData: [],
      showHistory: 0,
      showFromInvoice: '1',
      isLoading: false,
    };
  },
  created: async function () {
    var vm = this;
    if (vm.showFromInvoice === '1') {
      vm.fetchFlowData(vm.configurationId, vm.showHistory);
    }
  },
  methods: {
    fetchFlowData: async function (configurationId, showHistory = '0') {
      var vm = this;
      this.isLoading=true;
      var params = "configId=" + configurationId + "&clientId="+ this.clientId +"&includeParentNode=true&showHistory=" + showHistory +"&isBillingType="+ this.isBillingType;
      const response = await DataService.ShowFlowchartNew(params);
      if (response && response.data && response.data.length > 0) {
        this.flowData = response.data;
      }
      this.isLoading=false;
    },
    // ✅ CANVAS PRINT FUNCTION
    async printPage() {
      const element = document.getElementById("divNodeFlowChartNew");
      this.isLoading = true;

      const canvas = await html2canvas(element, {
        scale: 2,
        backgroundColor: "#ffffff",
        useCORS: true,
        scrollX: 0,
        scrollY: -window.scrollY
      });

      this.isLoading = false;

      const image = canvas.toDataURL("image/png");

      // Create hidden iframe
      const iframe = document.createElement("iframe");
      iframe.style.position = "fixed";
      iframe.style.right = "0";
      iframe.style.bottom = "0";
      iframe.style.width = "0";
      iframe.style.height = "0";
      iframe.style.border = "0";
      document.body.appendChild(iframe);

      const doc = iframe.contentWindow.document;
      doc.open();
      doc.write(`
        <html>
          <head>
            <title>Print</title>
            <style>
              body { margin: 0; text-align: center; }
              img { max-width: 100%; }
            </style>
          </head>
          <body>
            <img id="printImg" src="${image}" />
            <script>
              const img = document.getElementById('printImg');
              img.onload = function () {
                window.focus();
                window.print();
              };
            <\/script>
          </body>
        </html>
      `);
      doc.close();

      // Cleanup after print
      iframe.contentWindow.onafterprint = () => {
        document.body.removeChild(iframe);
      };
    }

  }
};
</script>
<style scoped>

#RflowChartNew {
  width: unset !important;

}
</style>