<template>
    <div>
        <ul class="nodechld mainlist ulnodellistdata ui-sortable border border-top-0" v-if="rules.length > 0">
            <li class="includenodechld userDragDrop bg-light brdrbtm position-relative ui-sortable-handle"
                v-for="(rule, index) in rules" v-if="rule.isDelete == false">
                <div class="collexpnd">
                    <span style="width: 22px;display: block;" v-if="rule.rules.length == 0"></span>
                    <a v-if="rule.rules.length > 0"
                        class="aCollapseExpand visible nodetablecollapse timesheetcollapse timesheetexpand expanded d-inline-block parent-childrow m-0"
                        href="javascript:;" v-on:click="rule.isShowChild = !rule.isShowChild">
                        <em
                            :class="{ 'fa': true, 'fa-chevron-up': (rule.isShowChild), 'fa-chevron-down': (!rule.isShowChild) }"></em>
                    </a>
                </div>
            
                <div class="content">
                    <label style="float: left; display: inline-block;">{{ rule.ruleName }} </label>
                    <span class="pl-2 float-left textelipsis" id="spn_1" :title="rule.ruleCondition.serviceName + ' ' + rule.ruleCondition.condition"
                        :style="(!child) ? 'color: rgb(103, 132, 168);' : 'color: rgb(118, 168, 28);'">
                        {{ rule.ruleCondition.serviceName }} {{ rule.ruleCondition.condition }}
                    </span>
                    <div class="text-right d-flex flex-wrap float-right">
                            <a class="mr-2 text-white node-a bg-success btnaddrule" href="javascript:;"
                                style="position: relative; z-index: 0;" :title="$t('AddRule')"
                                v-on:click="addRuleCondition(rule)" v-if="!rule.ruleCondition.conditionId && rule.ruleCondition.nodeName != 'GLOBAL'">
                                <em class="fa fa-plus pr-1 fa-size"></em> {{ $t("AddRule") }}
                            </a>
                            <a v-if="rule.ruleCondition.conditionId && mode === 'Edit' && rule.ruleCondition.nodeName != 'GLOBAL'" 
                                @click="EditRuleByConditionId(rule.ruleCondition)" 
                                class="mr-2 text-white node-a bg-success btnaddrule" 
                                href="javascript:;" 
                                style="position: relative; z-index: 0;" 
                                :title="$t('EditRule')">
                                <em class="fa fa-pencil pr-1 fa-size"></em> {{ $t("EditRule") }}
                            </a>
                            <a v-if="rule.ruleCondition.conditionId && mode === 'View' && rule.ruleCondition.nodeName != 'GLOBAL'" 
                                @click="EditRuleByConditionId(rule.ruleCondition)" 
                                class="mr-2 text-white node-a bg-success btnaddrule" 
                                href="javascript:;" 
                                style="position: relative; z-index: 0;" 
                                :title="$t('ViewRule')">
                                <em class="fa fa-eye pr-1 fa-size"></em> {{ $t("ViewRule") }}
                            </a>
                                                    
                            <a class="mr-2 text-white node-a bg-primary btnchildadd" v-if="rule.ruleCondition.nodeName != 'GLOBAL'"
                                :class="{ 'disabled': mode === 'View' }"
                                href="javascript:;"
                                style="position: relative; z-index: 0;"
                                :title="isBillingType ? $t('AddChild') : $t('AdditionalCondition')"
                                @click="mode === 'View' ? $event.preventDefault() : AddAdditionalCondition(rule)">
                                <em class="fa fa-plus-circle pr-1 fa-size"></em> {{ isBillingType ? $t('AddChild') : $t('AdditionalCondition') }}
                            </a>

                            <a class="mr-2 text-white node-a bg-info btnaddruleabove"  v-if="rule.ruleCondition.nodeName != 'GLOBAL'"
                                :class="{ 'disabled': mode === 'View' }"
                                href="javascript:;"
                                style="position: relative; z-index: 0;"
                                :title="$t('Insert_Above')"
                                @click="mode === 'View' ? $event.preventDefault() : InsertAbove(rule, index)">
                                <em class="fa fa-plus-circle pr-1 fa-size"></em> {{ $t("Insert_Above") }}
                            </a>

                            <a class="mr-2 text-white node-a bg-info btnaddrulebelow" v-if="rule.ruleCondition.nodeName != 'GLOBAL'"
                                :class="{ 'disabled': mode === 'View' }"
                                href="javascript:;"
                                style="position: relative; z-index: 0;"
                                :title="$t('Insert_Below')"
                                @click="mode === 'View' ? $event.preventDefault() : InsertBelow(rule, index)">
                                <em class="fa fa-plus-circle pr-1 fa-size"></em> {{ $t("Insert_Below") }}
                            </a>
                        <!-- start button div -->
                        <div class="buttonsdlt" style="float: right;" v-if="rule.ruleCondition.nodeName != 'GLOBAL'">
                            <!-- Delete Icon -->
                            <a class="aDelete enable deleteNodeConf mr-2"  :class="{ 'disabled': mode  === 'View' }" href="javascript:;" :data-node="1"
                                data-toggle-tooltip="tooltip" v-on:click="deleteRule(rule, index)"
                                title="Click here to delete this rule">
                                <em class="fa fa-trash-o text-danger fa-size"></em>
                            </a>
                        </div>
                        <div class="buttonsdlt ml-2" style="float: right;min-width: 40px;" v-if="mode != 'View' && rule.ruleCondition.nodeName != 'GLOBAL' && isBillingType != true">
                            <!-- Down arrow only for first item -->
                            <div v-if="index === 0 && rules[index].parent == null">
                                <a class=" aDelete enable deleteNodeConf ml-2" href="javascript:;"
                                    v-on:click="DecreaseIndex(rule, index, 'down')" data-original-title="Move down">
                                    <em class="fa fa-arrow-circle-down text-dark action-icon DownDisplayOrder "></em>
                                </a>
                            </div>
                            <!-- Both arrows for middle items -->
                            <div v-else-if="index > 0 && index < rules.length - 1 && rules[index].parent == null">
                                <a class="aDelete enable deleteNodeConf" href="javascript:;"
                                    v-on:click="IncreaseIndex(rule, index, 'up')" data-original-title="Move up">
                                    <em class="fa fa-arrow-circle-up text-dark action-icon UpDisplayOrder "></em>
                                </a>
                                <a class="aDelete enable deleteNodeConf ml-2" href="javascript:;"
                                    v-on:click="DecreaseIndex(rule, index, 'down')" data-original-title="Move down">
                                    <em class="fa fa-arrow-circle-down text-dark action-icon DownDisplayOrder "></em>
                                </a>
                            </div>
                            <!-- Up arrow only for last item -->
                            <div v-else-if="rules[index].parent == null">
                                <a class="aDelete enable deleteNodeConf ml-2" href="javascript:;"
                                    v-on:click="IncreaseIndex(rule, index, 'up')" data-original-title="Move up">
                                    <em class="fa fa-arrow-circle-up text-dark action-icon UpDisplayOrder "></em>
                                </a>
                            </div>
                        </div>
                    </div>
                </div>
                <!-- <div class="buttonsdlt" style="float: right;">
                    <a class="aDelete enable deleteNodeConf" href="javascript:;" data-node="1" title=""
                        data-toggle-tooltip="tooltip" v-on:click="deleteRule(rule, index)"
                        data-original-title="Click here to delete this rule">
                        <em class="fa fa-trash text-danger fa-size"></em>
                    </a>
                    <a class="aDelete enable deleteNodeConf" href="javascript:;" data-node="2" title=""
                        v-on:click="changeIndex(rule, index)" data-toggle-tooltip="tooltip"
                        data-original-title="Click here to delete this rule">
                        <em class="fas fa-angle-down text-success fa-size"></em>
                    </a>
                </div> -->
                <RecursiveNodeConfiguration
                    :name="'RecursiveNodeConfiguration' + rule.ruleDisplayOrder"
                    :rules="rule.rules"
                    :child="true"
                    :configurationId="configurationId"
                    :reqType="reqType"
                    :serviceId="serviceId"
                    :mode="mode"
                    :isBillingType="isBillingType"
                    :clientId="clientId"
                    :setupId="setupId"
                    v-show="rule.isShowChild"
                ></RecursiveNodeConfiguration>
            </li>
        </ul>
        <ServiceRuleCondition v-if="serviceDetailConditions" :serviceRuleItem="serviceRuleItem"
            v-on:close="serviceDetailConditions = false" :configurationId="configurationId" :reqType="reqType" 
            :serviceId="serviceId" :isBillingType="isBillingType" :clientId="clientId" :setupId="setupId"></ServiceRuleCondition>
        <ModalAddBillingRule v-if="isModalAddRule" :reqFrom="reqFrom" :serviceRuleItem="serviceRuleItem" :rateData="rateData"
            :configurationId="configurationId"
            :conditionId="conditionId" :nodeName="nodeName" @rule-saved="handleRuleSaved" viewType="recursiveNode" :serviceId="serviceId"  :mode="mode">
        </ModalAddBillingRule>
        <ManageBillingRuleForm v-if="isManageBillingRuleForm" :reqFrom="reqFrom" :serviceRuleItem="serviceRuleItem" :rateData="rateData"
             :configurationId="configurationId"
            :conditionId="conditionId" :nodeName="nodeName" @rule-saved="handleRuleSaved" viewType="recursiveNode" 
            :serviceId="serviceId" :setupId="setupId"  :mode="mode" :isBillingType="isBillingType" :clientId="clientId">
        </ManageBillingRuleForm>
    </div>
</template>
<script>
import ServiceRuleCondition from "./../../Plan/ServiceRules/ServiceRuleConditions.vue";
import RecursiveNodeConfiguration from "./RecursiveNodeConfiguration.vue";
import ModalAddBillingRule from "../../../components/Modals/modalAddBillingRule.vue";
import ManageBillingRuleForm from "../../../components/Modals/manageBillingRuleFormForUsic.vue";
export default {
    name: 'RecursiveNodeConfiguration',
    components: { ServiceRuleCondition, "RecursiveNodeConfiguration": RecursiveNodeConfiguration, ModalAddBillingRule,ManageBillingRuleForm },
    props: {
        rules: {
            type: Array,
            default: []
        },
        configurationId: {
            type: String,
            default: null
        },
        child: {
            type: Boolean,
            default: false
        }, 
        reqType: {
            type: String,
            default: false
        },
        serviceId:{
            type: String,
            default: false
        },
        mode :{
            type: String,
            default: 'Edit'

        },
        isBillingType :{
            type: Boolean,
            required: false
        },
        clientId:{
            type: Number,
            default: false
        },
         setupId:{
            type: Number,
            default: null
        }
        
    },
    data: function () {
        return {
            serviceDetailConditions: false,
            serviceRuleItem: null,
            isRuleView: false,
            isModalAddRule: false,
            reqFrom: '',
            conditionId: 0,
            nodeName: '',
            configurationId: 0,
            rateData:'',
            // mode:false,
            isManageBillingRuleForm: false,
        }
    },
    created:function(){
        var vm = this;
        if(this.$route.params.mode =='View'){
            vm.mode = 'View';
        }
    },
    methods: {
        handleRuleSaved(ruleData) {
            this.mergeRuleData(ruleData);
        },
        mergeRuleData(ruleData) {
            const rulesArray = this.rules; // already an Array (prop reference)
            const parsedRuleData = JSON.parse(ruleData);
            // Clean up unnecessary properties
            delete parsedRuleData.addAdderTypeTable;
            delete parsedRuleData.conditions;
            delete parsedRuleData.showPopup;

            // --- Add this block to bind values ---
            if (parsedRuleData.isLeaf !== undefined) {
                parsedRuleData.isLeafChecked = parsedRuleData.isLeaf;
            }

            if (parsedRuleData.workCodeId !== undefined) {
                parsedRuleData.rateCode = parsedRuleData.workCodeId;
            }

            delete parsedRuleData.isLeaf;
            delete parsedRuleData.workCodeId;

            const applied = this.applyRuleMerge(rulesArray, parsedRuleData);

            if (!applied) {
                console.warn("No matching rule Condition found.");
            }
        },
        // Recursively update the rule tree so child nodes also get updated
        applyRuleMerge(rulesArray, parsedRuleData) {
            for (let i = 0; i < rulesArray.length; i++) {
                const rule = rulesArray[i];
                if (rule.ruleCondition && rule.ruleCondition.conditionId === parsedRuleData.conditionId) {
                    this.$set(rule, 'ruleCondition', {
                        ...rule.ruleCondition,
                        ...parsedRuleData
                    });
                    return true;
                }
                if (Array.isArray(rule.rules) && rule.rules.length > 0) {
                    const updated = this.applyRuleMerge(rule.rules, parsedRuleData);
                    if (updated) return true;
                }
            }
            return false;
        },
        EditRuleByConditionId: function (conditionData) {
            var vm = this;
            debugger;
            vm.serviceId = this.serviceId;
            vm.conditionId = conditionData.conditionId;
            vm.nodeName = conditionData.nodeName;
            vm.rateData = (Array.isArray(conditionData?.ruleArray) && conditionData.ruleArray.length > 0) ? conditionData.ruleArray : conditionData;
            // vm.rateData = conditionData.ruleArray.length > 0 ? conditionData.ruleArray : conditionData;
            // vm.rateData = JSON.parse(conditionData.ruleArray);
            // vm.configurationId = parseInt(this.$route.params.id);
            vm.reqFrom = 'ViewBillingConditionForService';
            if(this.isBillingType == true){
                vm.isManageBillingRuleForm = true;
            }
            else{
                vm.isModalAddRule = true;
            }
        },
        AddAdditionalCondition: function (item) {
            if (item.ruleCondition.conditionId) {
                if (!item.ruleCondition.isLeafChecked) {
                    let version = this.getVersionValue(item);
                    item.rules.push({
                        ruleId: 0,
                        ruleDisplayOrder: (item.rules.length + 1),
                        ruleName: "Rule " + version,
                        version: version,
                        ruleCondition: {},
                        rules: [],
                        parent: item.version,
                        isDelete: false,
                        isShowChild: true,
                        hidebuttons: false
                    });
                } else {
                    this.ShowAlert(this.$t('NotAddChildMessage'), "warning", true, this.$t('Alert'));
                }
            }
            else {
                this.ShowAlert(this.$t('FillServiceAlertMessage'), "warning", true, this.$t('Alert'));
            }
        },
        addRuleCondition: function (item, serviceData) {
            item.reqFrom = '';
            this.serviceId = this.serviceId;
            this.serviceDetailConditions = !this.serviceDetailConditions;
            this.serviceRuleItem = item;
        },
        deleteRule: function (rl, index) {
            let ths = this;
            ths.confirmR(ths.$t("ConfirmDeleteRecord"), true, (ths.$t("Detete")), async function () {
                if (rl.ruleId > 0) {
                    rl.isDelete = true;
                } else {
                    ths.rules.splice(index, 1);
                }
            });
        },
        IncreaseIndex(rule, index) {
            const vm = this;
            const newIndex = index - 1;
            if (newIndex < 0) return;
            const currentRule = JSON.parse(JSON.stringify(vm.rules[index]));
            const targetRule = JSON.parse(JSON.stringify(vm.rules[newIndex]));
            vm.$set(vm.rules, newIndex, currentRule);
            vm.$set(vm.rules, index, targetRule);
            vm.rules.forEach((item, idx) => {
                item.ruleDisplayOrder = idx + 1;
                item.version = `${idx + 1}`;
                item.ruleName = `Rule ${item.version}`;
                item.parent = null;
                if (Array.isArray(item.rules)) {
                    this.updateNestedVersions(item.rules, item.version);
                }
            });
        },
        DecreaseIndex(rule, index) {
            const vm = this;
            const newIndex = index + 1;
            if (newIndex >= vm.rules.length) return;
            const currentRule = JSON.parse(JSON.stringify(vm.rules[index]));
            const targetRule = JSON.parse(JSON.stringify(vm.rules[newIndex]));
            vm.$set(vm.rules, newIndex, currentRule);
            vm.$set(vm.rules, index, targetRule);
            vm.rules.forEach((item, idx) => {
                item.ruleDisplayOrder = idx + 1;
                item.version = `${idx + 1}`;
                item.ruleName = `Rule ${item.version}`;
                item.parent = null;
                if (Array.isArray(item.rules)) {
                    this.updateNestedVersions(item.rules, item.version);
                }
            });
        },
        updateNestedVersions(rules, parentVersion) {
            rules.forEach((rule, idx) => {
                const version = `${parentVersion}.${idx + 1}`;
                rule.version = version;
                rule.ruleName = `Rule ${version}`;
                rule.ruleDisplayOrder = idx + 1;
                rule.parent = parentVersion;
                if (Array.isArray(rule.rules) && rule.rules.length > 0) {
                    this.updateNestedVersions(rule.rules, version);
                }
            });
        },
        deepClone(obj) {
            return JSON.parse(JSON.stringify(obj));
        },
        InsertAbove: function (rl, index) {
            if (index == 0) {
                this.ShowAlert(this.$t("AboveNodeAlertMessage", [" " + rl.version]), "failure", this.$t('Alert'));
            } else {
                this.rules.splice((index), 0, {
                    ruleId: 0,
                    ruleDisplayOrder: 1,
                    ruleName: "Rule " + 1,
                    version: 1,
                    ruleCondition: {},
                    rules: [],
                    parent: rl.parent,
                    isShowChild: true,
                    isDelete: false
                });
                this.redefineRuleVersions(rl.parent);
            }
        },
        InsertBelow: function (rl, index) {
            this.rules.splice((index + 1), 0, {
                ruleId: 0,
                ruleDisplayOrder: 1,
                ruleName: "Rule " + 1,
                version: 1,
                ruleCondition: {},
                rules: [],
                parent: rl.parent,
                isShowChild: true,
                isDelete: false
            });
            this.redefineRuleVersions(rl.parent);
        },
        getVersionValue: function (item) {
            var version = item.version;
            if (item.rules.length > 0) {
                version = item.rules[item.rules.length - 1].version;
                version = (version.substring(0, version.lastIndexOf("."))) + ("." + (parseInt(version.substring(version.lastIndexOf(".") + 1)) + 1));
            } else {
                var version = item.version + ".1";
            }
            return version;
        },
        redefineRuleVersions: function (prnt) {
            var prefix = "";
            this.rules.forEach(function (item, index) {
                item.ruleDisplayOrder = (index + 1);
                if (prnt == null) {
                    item.version = (index + 1);
                    item.ruleName = "Rule " + (index + 1);
                } else {
                    item.version = prnt + "." + (index + 1);
                    item.ruleName = "Rule " + prnt + "." + (index + 1);
                }
            });
        }
    },
}
</script>
<style>
a.disabled {
  opacity: 0.6;               
  color: #ffffff !important;  
}
</style>

